module testbench_00629144;
    reg [783:0] inp = 0;
    wire [109:0] outp;
    reg [783:0] inp_inv = 0;

    // Unit under test (UUT)
   logic_network_00629144 uut (
   .clk(clk),
       .inp (inp),
       .outp (outp)
   );


    integer file_id, r, i, j;
    integer groups[10:0];
    reg [10:0] classes [9:0]; 
    reg test_passed;

    initial 
    begin
        inp = 0;
        file_id = $fopen({"/path/to/in_out.csv"}, "r");
        if (file_id == 0) begin
            $display("Error opening file");
            $finish;
        end

        while (!$feof(file_id)) begin
            r = $fscanf(file_id, "%b,%d,%d,%d,%d,%d,%d,%d,%d,%d,%d,%d", inp_inv, groups[0], groups[1], groups[2], groups[3], groups[4], groups[5], groups[6], groups[7], groups[8], groups[9], groups[10]);

        // Inverse bits from Torch output. Only partially reverse
			for (i=0; i < 784; i= i+ 1) begin
                inp[i]=inp_inv[784 -1 -i];
            end

            $display("Read %d values", r);
            $display("%b", inp);

            #10 
            for (i=0; i < 10; i = i+1) begin
                classes[i] = outp[i*11 +: 11];
            end

            #1
            test_passed = 1;
            for (i=0; i < 10; i = i+1) begin
                if(classes[i] !== groups[i]) begin
                   $display("Mismatch in popcount. measured %d, should be %d", classes[i], groups[i]);
                   test_passed = 0;
                end
            end

            if (test_passed) begin
                $display("Test passed");
            end
        end 

        #5 $finish;
    end 
endmodule

